{
  "description": "This quiz tests foundational SQL querying abilities, challenging developers to write raw queries without relying on ORM abstractions. It targets a beginner-to-intermediate difficulty level and uses a casual, encouraging tone to help programmers confidently refresh their database skills.",
  "topics": [
    "SQL Fundamentals",
    "Raw Database Querying",
    "ORM Independence",
    "Data Retrieval"
  ],
  "audience": "Software developers and backend engineers who use ORMs and want to validate or improve their direct SQL proficiency"
}
